from typing import NamedTuple

class ClearErrorsResult(NamedTuple):
    error_out: dict

def clear_errors(error_in: dict = None) -> ClearErrorsResult:
    """Clear any errors, returning a clean error cluster."""
    return ClearErrorsResult(error_out={'status': False, 'code': 0, 'source': ''})

from typing import NamedTuple

class ErrorClusterFromCodeResult(NamedTuple):
    error_out: dict

def error_cluster_from_code(code: int, source: str = '') -> ErrorClusterFromCodeResult:
    """Create error cluster from error code."""
    return ErrorClusterFromCodeResult(error_out={'status': code != 0, 'code': code, 'source': source})
